using System.ComponentModel;
using Microsoft.Extensions.AI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

var notebook = new Notebook();

IChatClient client = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var tools = new AITool[]
{
    AIFunctionFactory.Create(WebSearchTool.SearchAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

List<ChatMessage> messages =
[
    new(ChatRole.System, """
        You are a research agent. Follow these steps:
        1. Search the web for relevant information on the topic. Perform multiple
           searches with different queries to get comprehensive coverage.
        2. As you find useful information, save notes using the add_note tool.
        3. After gathering enough information, retrieve your notes and write a
           well-structured summary with key findings and source URLs.
        Be thorough but concise. Always cite sources.
        """),
    new(ChatRole.User, $"Research this topic and provide a comprehensive summary: {topic}")
];

var options = new ChatOptions { Tools = tools };

Console.WriteLine("⏳ Agent is searching and gathering information...\n");

var response = await client.GetResponseAsync(messages, options);

Console.WriteLine("📋 Research Summary:\n");
Console.WriteLine(response);

