using System.ComponentModel;
using System.Text.Json;
using System.Web;

/// <summary>
/// Searches the web using the DuckDuckGo Instant Answer API.
/// For production use, swap in a full search API (Bing, Google, Brave, etc.).
/// </summary>
public static class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } }
    };

    [Description("Searches the web and returns results with titles, URLs, and snippets")]
    public static async Task<IReadOnlyList<SearchResult>> SearchAsync(
        [Description("The search query")] string query)
    {
        var encoded = HttpUtility.UrlEncode(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        var json = await Http.GetFromJsonAsync<JsonElement>(url);
        var results = new List<SearchResult>();

        var abstractText = json.GetProperty("Abstract").GetString();
        var abstractUrl = json.GetProperty("AbstractURL").GetString();
        var abstractSource = json.GetProperty("AbstractSource").GetString();

        if (!string.IsNullOrEmpty(abstractText))
        {
            results.Add(new SearchResult(
                $"{abstractSource} (Summary)",
                abstractUrl ?? "",
                abstractText));
        }

        if (json.TryGetProperty("RelatedTopics", out var topics))
        {
            foreach (var topic in topics.EnumerateArray())
            {
                if (topic.TryGetProperty("Text", out var text) &&
                    topic.TryGetProperty("FirstURL", out var topicUrl))
                {
                    results.Add(new SearchResult(
                        text.GetString()?[..Math.Min(text.GetString()!.Length, 80)] ?? "Related",
                        topicUrl.GetString() ?? "",
                        text.GetString() ?? ""));
                }

                if (topic.TryGetProperty("Topics", out var subTopics))
                {
                    foreach (var sub in subTopics.EnumerateArray())
                    {
                        if (sub.TryGetProperty("Text", out var subText) &&
                            sub.TryGetProperty("FirstURL", out var subUrl))
                        {
                            results.Add(new SearchResult(
                                subText.GetString()?[..Math.Min(subText.GetString()!.Length, 80)] ?? "Related",
                                subUrl.GetString() ?? "",
                                subText.GetString() ?? ""));
                        }
                    }
                }
            }
        }

        if (results.Count == 0)
        {
            results.Add(new SearchResult(
                "No results",
                "",
                $"No instant results for '{query}'. Try rephrasing the search."));
        }

        return results;
    }
}

public record SearchResult(string Title, string Url, string Snippet);

using System.ComponentModel;

/// <summary>
/// A simple in-memory notebook that the agent uses to record findings.
/// </summary>
public sealed class Notebook
{
    private readonly List<Note> _notes = [];

    [Description("Saves a research note with a title and content for later reference")]
    public string AddNote(
        [Description("Title for the note")] string title,
        [Description("Content of the note")] string content)
    {
        _notes.Add(new Note(title, content, DateTime.UtcNow));
        return $"Note '{title}' saved. Total notes: {_notes.Count}";
    }

    [Description("Retrieves all saved research notes")]
    public IReadOnlyList<Note> GetNotes() => _notes.AsReadOnly();
}

public record Note(string Title, string Content, DateTime SavedAt);

