using System.ComponentModel;

/// <summary>
/// A simple in-memory notebook that the agent uses to record findings.
/// </summary>
public sealed class Notebook
{
    private readonly List<Note> _notes = [];

    [Description("Saves a research note with a title and content for later reference")]
    public string AddNote(
        [Description("Title for the note")] string title,
        [Description("Content of the note")] string content)
    {
        _notes.Add(new Note(title, content, DateTime.UtcNow));
        return $"Note '{title}' saved. Total notes: {_notes.Count}";
    }

    [Description("Retrieves all saved research notes")]
    public IReadOnlyList<Note> GetNotes() => _notes.AsReadOnly();
}

public record Note(string Title, string Content, DateTime SavedAt);

